# Let's check various locations where the attachment might be
import os
import glob
import subprocess

print("Looking for the audio file...")

# Check various possible locations
possible_locations = [
    '/tmp/',
    '/tmp/attachment',
    '/attachments/',
    './',
    '../',
    '/workspace/',
    '/home/',
    '/var/',
    '/opt/'
]

found_files = []
for location in possible_locations:
    if os.path.exists(location):
        print(f"Checking {location}:")
        try:
            if os.path.isdir(location):
                files = os.listdir(location)
                for f in files:
                    if f.endswith('.mp3') or 'mp3' in f.lower() or 'audio' in f.lower():
                        full_path = os.path.join(location, f)
                        found_files.append(full_path)
                        print(f"  Found: {full_path}")
            else:
                # Check if this is the file itself
                if location.endswith('.mp3'):
                    found_files.append(location)
                    print(f"  Found: {location}")
        except Exception as e:
            print(f"  Error accessing {location}: {e}")

print(f"\nTotal found files: {len(found_files)}")

# Also search more broadly
print("\nSearching entire filesystem for MP3 files (limited search)...")
try:
    # Use find command to search for mp3 files
    result = subprocess.run(['find', '/', '-name', '*.mp3', '-type', 'f'], 
                          capture_output=True, text=True, timeout=10)
    if result.stdout:
        mp3_files = result.stdout.strip().split('\n')
        for mp3_file in mp3_files:
            if mp3_file and mp3_file not in found_files:
                found_files.append(mp3_file)
                print(f"  Found via find: {mp3_file}")
except Exception as e:
    print(f"Find command failed: {e}")

if found_files:
    print(f"\nAll found audio files: {found_files}")
else:
    print("\nNo MP3 files found. Let me check if the attachment was passed differently...")

